+    let stream = unsafe { tmpfile64() };
+    assert!(!stream.is_null());
+    let data = b"test64";
+    let written = unsafe { fwrite(data.as_ptr().cast(), 1, data.len(), stream) };
+    assert_eq!(written, data.len());
+    assert_eq!(unsafe { fclose(stream) }, 0);
+}
